DROP MATERIALIZED VIEW "public"."all_games";--> statement-breakpoint
ALTER TABLE "game" RENAME COLUMN "info_gen" TO "clue";--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."all_games" AS (select "id", "igdb_id", "name", "image_url", "ai_image_url", "ai_prompt", "image_gen", "clue", "artworks", "keywords", "franchises", "game_engines", "game_modes", "genres", "involved_companies", "platforms", "player_perspectives", "release_dates", "themes", "first_release_date", "summary", "storyline", "created_at" from "game" order by "game"."name");